     1→// web/app/page.tsx
     2→"use client";
     3→
     4→import { useEffect } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { StatsCards } from "@/components/dashboard/stats-cards";
     7→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     8→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
     9→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    10→import { projects as projectsApi } from "@/lib/api/client";
    11→
    12→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    13→
    14→export default function DashboardPage() {
    15→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    16→    projectsApi.list()
    17→  );
    18→
    19→  // Listen to SSE events and revalidate dashboard data on new releases
    20→  useEffect(() => {
    21→    let es: EventSource | null = null;
    22→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    23→
    24→    function connect() {
    25→      try {
    26→        es = new EventSource(`${SSE_BASE}/events`);
    27→        es.onmessage = () => {
    28→          // Revalidate all dashboard SWR keys on any event
    29→          mutate((key) => typeof key === "string" && (
    30→            key === "stats" ||
    31→            key.startsWith("trend-") ||
    32→            key === "unified-feed"
    33→          ), undefined, { revalidate: true });
    34→        };
    35→        es.onerror = () => {
    36→          es?.close();
    37→          retryTimer = setTimeout(connect, 5000);
    38→        };
    39→      } catch {
    40→        retryTimer = setTimeout(connect, 5000);
    41→      }
    42→    }
    43→
    44→    connect();
    45→    return () => {
    46→      es?.close();
    47→      if (retryTimer) clearTimeout(retryTimer);
    48→    };
    49→  }, []);
    50→
    51→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    52→
    53→  return (
    54→    <div className="space-y-6">
    55→      <h1
    56→        style={{
    57→          fontFamily: "var(--font-fraunces)",
    58→          fontSize: "24px",
    59→          fontWeight: 700,
    60→          color: "#111113",
    61→        }}
    62→      >
    63→        Dashboard
    64→      </h1>
    65→
    66→      {hasProjects ? (
    67→        <>
    68→          <StatsCards />
    69→          <div className="grid gap-4 lg:grid-cols-2">
    70→            <ReleaseTrendChart />
    71→            <UnifiedFeed />
    72→          </div>
    73→        </>
    74→      ) : isLoading ? (
    75→        <div
    76→          className="py-16 text-center"
    77→          style={{
    78→            fontFamily: "var(--font-dm-sans)",
    79→            fontSize: "13px",
    80→            color: "#6b7280",
    81→          }}
    82→        >
    83→          Loading...
    84→        </div>
    85→      ) : (
    86→        <DashboardEmptyState />
    87→      )}
    88→    </div>
    89→  );
    90→}
