   669→              <button
   670→                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
   671→                disabled={currentPage >= totalPages}
   672→                className="rounded-md border px-3 py-1 text-[13px] transition-colors disabled:opacity-40"
   673→                style={{ borderColor: "#e8e8e5", color: "#374151", fontFamily: "var(--font-dm-sans)" }}
   674→              >
   675→                Next
   676→              </button>
   677→            </div>
   678→          )}
   679→        </>
   680→      )}
   681→
   682→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   683→        <DialogContent className="sm:max-w-lg">
   684→          <DialogHeader>
   685→            <DialogTitle>Create Project</DialogTitle>
