     1→// web/components/dashboard/unified-feed.tsx
     2→"use client";
     3→
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import {
     7→  projects as projectsApi,
     8→  releases as releasesApi,
     9→  sources as sourcesApi,
    10→  semanticReleases as srApi,
    11→} from "@/lib/api/client";
    12→import { VersionChip } from "@/components/ui/version-chip";
    13→import { getProviderIcon } from "@/components/ui/provider-badge";
    14→import { Sparkles } from "lucide-react";
    15→import type { Release, SemanticRelease, Source } from "@/lib/api/types";
    16→import { timeAgo } from "@/lib/format";
    17→
    18→type FeedItemType =
    19→  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
    20→  | { kind: "semantic"; data: SemanticRelease; projectName?: string };
    21→
    22→function getTimestamp(item: FeedItemType): number {
    23→  if (item.kind === "release") {
    24→    return new Date(item.data.released_at ?? item.data.created_at).getTime();
    25→  }
    26→  return new Date(item.data.created_at).getTime();
    27→}
    28→
    29→function getTimeStr(item: FeedItemType): string {
    30→  if (item.kind === "release") {
    31→    return item.data.released_at ?? item.data.created_at;
    32→  }
    33→  return item.data.created_at;
    34→}
    35→
    36→function ProviderIcon({ provider }: { provider: string }) {
    37→  const icon = getProviderIcon(provider);
    38→  if (!icon) return <div className="h-3.5 w-3.5 shrink-0" />;
    39→  return icon({ size: 14, className: "shrink-0", style: { color: "#9ca3af" } });
    40→}
    41→
    42→export function UnifiedFeed() {
    43→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    44→    projectsApi.list()
    45→  );
    46→
    47→  const { data: feedItems, isLoading } = useSWR(
    48→    projectsData ? "unified-feed" : null,
    49→    async () => {
    50→      if (!projectsData?.data?.length) return [];
    51→
    52→      const projectMap = new Map(
    53→        projectsData.data.map((p) => [p.id, p.name])
    54→      );
    55→      const projectSlice = projectsData.data.slice(0, 10);
    56→
    57→      // Fetch releases, sources, and semantic releases in parallel
    58→      const [releaseResults, sourceResults, srResults] = await Promise.all([
    59→        Promise.all(
    60→          projectSlice.map((p) =>
    61→            releasesApi.listByProject(p.id, 1).catch(() => null)
    62→          )
    63→        ),
    64→        Promise.all(
    65→          projectSlice.map((p) =>
    66→            sourcesApi.listByProject(p.id, 1).catch(() => null)
    67→          )
    68→        ),
    69→        Promise.all(
    70→          projectSlice.map((p) =>
    71→            srApi.list(p.id, 1).catch(() => null)
    72→          )
    73→        ),
    74→      ]);
    75→
    76→      // Build source lookup maps
    77→      const sourceMap = new Map<string, string>();
    78→      const providerMap = new Map<string, string>();
    79→      const sourceProjectMap = new Map<string, string>();
    80→      sourceResults
    81→        .filter((r): r is NonNullable<typeof r> => r !== null)
    82→        .flatMap((r) => r.data)
    83→        .forEach((s: Source) => {
    84→          sourceMap.set(s.id, s.repository);
    85→          providerMap.set(s.id, s.provider);
    86→          sourceProjectMap.set(s.id, s.project_id);
    87→        });
    88→
    89→      // Build feed items
    90→      const items: FeedItemType[] = [];
    91→
    92→      releaseResults
    93→        .filter((r): r is NonNullable<typeof r> => r !== null)
    94→        .flatMap((r) => r.data)
    95→        .forEach((rel) => {
    96→          const projectId = sourceProjectMap.get(rel.source_id);
    97→          items.push({
    98→            kind: "release",
    99→            data: rel,
   100→            repository: sourceMap.get(rel.source_id),
   101→            provider: providerMap.get(rel.source_id),
   102→            projectName: projectId ? projectMap.get(projectId) : undefined,
   103→          });
   104→        });
   105→
   106→      srResults
   107→        .filter((r): r is NonNullable<typeof r> => r !== null)
   108→        .flatMap((r) => r.data)
   109→        .forEach((sr) => {
   110→          items.push({
   111→            kind: "semantic",
   112→            data: sr,
   113→            projectName: projectMap.get(sr.project_id),
   114→          });
   115→        });
   116→
   117→      // Sort by timestamp descending, take first 15
   118→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
   119→      return items.slice(0, 15);
   120→    },
   121→    { refreshInterval: 30_000 }
   122→  );
   123→
   124→  if (isLoading) {
   125→    return (
   126→      <div
   127→        className="rounded-lg bg-white py-16 text-center"
   128→        style={{ border: "1px solid #e8e8e5" }}
   129→      >
   130→        <p
   131→          style={{
   132→            fontFamily: "var(--font-dm-sans)",
   133→            fontSize: "13px",
   134→            color: "#6b7280",
   135→          }}
   136→        >
   137→          Loading activity...
   138→        </p>
   139→      </div>
   140→    );
   141→  }
   142→
   143→  if (!feedItems || feedItems.length === 0) {
   144→    return null; // Empty state handled by parent
   145→  }
   146→
   147→  return (
   148→    <div
   149→      className="flex flex-col rounded-lg bg-white"
   150→      style={{ border: "1px solid #e8e8e5", height: "336px" }}
   151→    >
   152→      {/* Header */}
   153→      <div
   154→        className="flex items-center justify-between px-5 py-4 shrink-0"
   155→        style={{ borderBottom: "1px solid #e8e8e5" }}
   156→      >
   157→        <p
   158→          className="text-xs uppercase tracking-[0.08em]"
   159→          style={{
   160→            fontFamily: "var(--font-dm-sans)",
   161→            fontSize: "12px",
   162→            color: "#6b7280",
   163→          }}
   164→        >
   165→          Recent Activity
   166→        </p>
   167→      </div>
   168→
   169→      {/* Feed items — scrollable */}
   170→      <div className="flex-1 overflow-y-auto">
   171→        {feedItems.map((item, idx) => (
   172→          <FeedEntry
   173→            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
   174→            item={item}
   175→            isLast={idx === feedItems.length - 1}
   176→          />
   177→        ))}
   178→      </div>
   179→    </div>
   180→  );
   181→}
   182→
   183→function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
   184→  if (item.kind === "semantic") {
   185→    const sr = item.data;
   186→    const urgency = sr.report?.urgency?.toUpperCase();
   187→    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";
   188→
   189→    return (
   190→      <Link
   191→        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
   192→        className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
   193→        style={{
   194→          borderBottom: isLast ? undefined : "1px solid #e8e8e5",
   195→        }}
   196→      >
   197→        {/* AI icon */}
   198→        <Sparkles className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />
   199→
   200→        {/* Content */}
   201→        <div className="min-w-0 flex-1 flex items-center gap-2">
   202→          <span
   203→            className="truncate"
   204→            style={{
   205→              fontFamily: "var(--font-dm-sans)",
   206→              fontSize: "13px",
   207→              color: "#6b7280",
   208→            }}
   209→          >
   210→            {item.projectName ?? "Unknown Project"}
   211→          </span>
   212→          {isUrgent && (
   213→            <span
   214→              className="inline-flex items-center rounded px-1 py-0.5 text-[10px] font-semibold leading-none"
   215→              style={{
   216→                backgroundColor: urgency === "CRITICAL" ? "#fff1f2" : "#fff8f0",
   217→                color: urgency === "CRITICAL" ? "#dc2626" : "#d97706",
   218→              }}
   219→            >
   220→              {urgency}
   221→            </span>
   222→          )}
   223→        </div>
   224→
   225→        {/* Version + timestamp */}
   226→        <div className="flex items-center gap-3 shrink-0">
   227→          <VersionChip version={sr.version} />
   228→          <span
   229→            className="whitespace-nowrap"
   230→            style={{
   231→              fontFamily: "var(--font-dm-sans)",
   232→              fontSize: "12px",
   233→              color: "#9ca3af",
   234→            }}
   235→          >
   236→            {timeAgo(getTimeStr({ kind: "semantic", data: sr }))}
   237→          </span>
   238→        </div>
   239→      </Link>
   240→    );
   241→  }
   242→
   243→  // Raw release
   244→  const release = item.data;
   245→
   246→  return (
   247→    <Link
   248→      href={`/releases/${release.id}`}
   249→      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
