    40→// HealthHandler implements HTTP handlers for health and stats endpoints.
    41→type HealthHandler struct {
    42→	checker HealthChecker
    43→}
    44→
    45→// NewHealthHandler returns a new HealthHandler.
    46→func NewHealthHandler(checker HealthChecker) *HealthHandler {
    47→	return &HealthHandler{checker: checker}
    48→}
    49→
    50→// Check handles GET /health — pings the database and returns health status.
    51→func (h *HealthHandler) Check(w http.ResponseWriter, r *http.Request) {
    52→	err := h.checker.PingDB(r.Context())
    53→	if err != nil {
    54→		RespondJSON(w, r, http.StatusServiceUnavailable, map[string]any{
    55→			"status": "unhealthy",
    56→			"checks": map[string]string{
    57→				"database": "error",
    58→			},
    59→		})
    60→		return
    61→	}
    62→	RespondJSON(w, r, http.StatusOK, map[string]any{
    63→		"status": "healthy",
    64→		"checks": map[string]string{
    65→			"database": "ok",
    66→		},
    67→	})
    68→}
