    70→// Stats handles GET /stats — returns aggregate dashboard statistics.
    71→func (h *HealthHandler) Stats(w http.ResponseWriter, r *http.Request) {
    72→	stats, err := h.checker.GetStats(r.Context())
    73→	if err != nil {
    74→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to retrieve stats")
    75→		return
    76→	}
    77→	RespondJSON(w, r, http.StatusOK, stats)
    78→}
    79→
    80→// Trend handles GET /api/v1/stats/trend — returns time-bucketed release counts.
    81→// Query params:
    82→//   - granularity: "daily" (default), "weekly", or "monthly"
    83→//   - days: number of days to look back (default 7, max 365)
    84→func (h *HealthHandler) Trend(w http.ResponseWriter, r *http.Request) {
    85→	granularity := r.URL.Query().Get("granularity")
    86→	if granularity == "" {
    87→		granularity = "daily"
    88→	}
    89→
    90→	switch granularity {
    91→	case "daily", "weekly", "monthly":
    92→	default:
    93→		RespondError(w, r, http.StatusBadRequest, "invalid_granularity", "granularity must be daily, weekly, or monthly")
    94→		return
    95→	}
    96→
    97→	days := 7
    98→	if d := r.URL.Query().Get("days"); d != "" {
    99→		parsed, err := strconv.Atoi(d)
   100→		if err != nil || parsed < 1 || parsed > 365 {
   101→			RespondError(w, r, http.StatusBadRequest, "invalid_days", "days must be an integer between 1 and 365")
   102→			return
   103→		}
   104→		days = parsed
   105→	}
   106→
   107→	now := time.Now().UTC()
   108→	start := now.AddDate(0, 0, -days)
   109→
   110→	buckets, err := h.checker.GetTrend(r.Context(), granularity, start, now)
   111→	if err != nil {
   112→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to retrieve trend data")
   113→		return
   114→	}
   115→
   116→	RespondJSON(w, r, http.StatusOK, TrendResponse{
   117→		Granularity: granularity,
   118→		Buckets:     buckets,
   119→	})
   120→}
