  );

  // Fetch existing projects to detect already-tracked repos
  const { data: existingProjects, mutate: mutateProjects } = useSWR(
    "projects-all",
    () => projectsApi.list(1, 100),
    { revalidateOnFocus: false }
  );

  const trackedRepos = new Set<string>([
