     3→import (
     4→	"encoding/json"
     5→	"fmt"
     6→	"net/http"
     7→	"sync"
     8→	"time"
     9→)
    10→
    11→const discoverCacheTTL = 1 * time.Hour
    12→
    13→// DiscoverItem represents a single repository/image result from a discovery search.
    14→type DiscoverItem struct {
    15→	Name        string `json:"name"`
    16→	FullName    string `json:"full_name"`
    17→	Description string `json:"description"`
    18→	Stars       int    `json:"stars"`
    19→	Language    string `json:"language,omitempty"`
    20→	URL         string `json:"url"`
    21→	AvatarURL   string `json:"avatar_url,omitempty"`
    22→	Provider    string `json:"provider"`
    23→}
    24→
    25→type cachedResult struct {
    26→	items     []DiscoverItem
    27→	fetchedAt time.Time
    28→}
    29→
    30→// DiscoverHandler implements HTTP handlers for the /discover resource.
    31→type DiscoverHandler struct {
    32→	client       *http.Client
    33→	githubURL    string
    34→	dockerHubURL string
    35→	mu           sync.Mutex
    36→	cache        map[string]cachedResult
    37→}
    38→
    39→// NewDiscoverHandler returns a new DiscoverHandler. Empty URL strings default
    40→// to the real GitHub / Docker Hub API base URLs.
    41→func NewDiscoverHandler(client *http.Client, githubURL, dockerHubURL string) *DiscoverHandler {
    42→	if githubURL == "" {
    43→		githubURL = "https://api.github.com"
    44→	}
    45→	if dockerHubURL == "" {
    46→		dockerHubURL = "https://hub.docker.com"
    47→	}
    48→	return &DiscoverHandler{
    49→		client:       client,
    50→		githubURL:    githubURL,
    51→		dockerHubURL: dockerHubURL,
    52→		cache:        make(map[string]cachedResult),
    53→	}
    54→}
    55→
    56→func (h *DiscoverHandler) getCached(key string) ([]DiscoverItem, bool) {
    57→	h.mu.Lock()
    58→	defer h.mu.Unlock()
    59→	c, ok := h.cache[key]
    60→	if !ok || time.Since(c.fetchedAt) > discoverCacheTTL {
    61→		return nil, false
    62→	}
    63→	return c.items, true
    64→}
    65→
    66→func (h *DiscoverHandler) setCache(key string, items []DiscoverItem) {
    67→	h.mu.Lock()
    68→	defer h.mu.Unlock()
    69→	h.cache[key] = cachedResult{items: items, fetchedAt: time.Now()}
    70→}
    71→
    72→// GitHub handles GET /discover/github — searches GitHub repositories.
    73→func (h *DiscoverHandler) GitHub(w http.ResponseWriter, r *http.Request) {
    74→	q := r.URL.Query().Get("q")
    75→	language := r.URL.Query().Get("language")
    76→
    77→	cacheKey := fmt.Sprintf("github:%s:%s", q, language)
    78→	if items, ok := h.getCached(cacheKey); ok {
    79→		RespondJSON(w, r, http.StatusOK, items)
    80→		return
    81→	}
    82→
    83→	searchQ := q
    84→	if language != "" {
    85→		searchQ = fmt.Sprintf("%s language:%s", q, language)
    86→	}
    87→
    88→	url := fmt.Sprintf("%s/search/repositories?q=%s&sort=stars&order=desc&per_page=25", h.githubURL, searchQ)
    89→	resp, err := h.client.Get(url)
    90→	if err != nil {
    91→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach GitHub API")
    92→		return
    93→	}
    94→	defer resp.Body.Close()
    95→
    96→	if resp.StatusCode != http.StatusOK {
    97→		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("GitHub API returned %d", resp.StatusCode))
    98→		return
    99→	}
   100→
   101→	var ghResp struct {
   102→		Items []struct {
   103→			Name        string `json:"name"`
   104→			FullName    string `json:"full_name"`
   105→			Description string `json:"description"`
   106→			Stars       int    `json:"stargazers_count"`
   107→			Language    string `json:"language"`
   108→			HTMLURL     string `json:"html_url"`
   109→			Owner       struct {
   110→				AvatarURL string `json:"avatar_url"`
   111→			} `json:"owner"`
   112→		} `json:"items"`
   113→	}
   114→	if err := json.NewDecoder(resp.Body).Decode(&ghResp); err != nil {
   115→		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse GitHub response")
   116→		return
   117→	}
   118→
   119→	items := make([]DiscoverItem, 0, len(ghResp.Items))
   120→	for _, repo := range ghResp.Items {
   121→		items = append(items, DiscoverItem{
   122→			Name:        repo.Name,
   123→			FullName:    repo.FullName,
   124→			Description: repo.Description,
   125→			Stars:       repo.Stars,
   126→			Language:    repo.Language,
   127→			URL:         repo.HTMLURL,
   128→			AvatarURL:   repo.Owner.AvatarURL,
   129→			Provider:    "github",
   130→		})
   131→	}
   132→
   133→	h.setCache(cacheKey, items)
   134→	RespondJSON(w, r, http.StatusOK, items)
   135→}
   136→
   137→// DockerHub handles GET /discover/dockerhub — searches Docker Hub repositories.
   138→func (h *DiscoverHandler) DockerHub(w http.ResponseWriter, r *http.Request) {
   139→	q := r.URL.Query().Get("q")
   140→	if q == "" {
   141→		q = "nginx"
   142→	}
   143→
   144→	cacheKey := fmt.Sprintf("dockerhub:%s", q)
   145→	if items, ok := h.getCached(cacheKey); ok {
   146→		RespondJSON(w, r, http.StatusOK, items)
   147→		return
   148→	}
   149→
   150→	url := fmt.Sprintf("%s/v2/search/repositories/?query=%s&page_size=25", h.dockerHubURL, q)
   151→	resp, err := h.client.Get(url)
   152→	if err != nil {
   153→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach Docker Hub API")
   154→		return
   155→	}
   156→	defer resp.Body.Close()
   157→
   158→	if resp.StatusCode != http.StatusOK {
   159→		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("Docker Hub API returned %d", resp.StatusCode))
   160→		return
   161→	}
   162→
   163→	var dhResp struct {
   164→		Results []struct {
   165→			RepoName         string `json:"repo_name"`
   166→			ShortDescription string `json:"short_description"`
   167→			StarCount        int    `json:"star_count"`
