   185→			FullName:    fullName,
   186→			Description: repo.ShortDescription,
   187→			Stars:       repo.StarCount,
   188→			URL:         fmt.Sprintf("https://hub.docker.com/_/%s", repo.RepoName),
   189→			Provider:    "dockerhub",
   190→		})
   191→	}
   192→
   193→	h.setCache(cacheKey, items)
   194→	RespondJSON(w, r, http.StatusOK, items)
   195→}
